import re
import math

# Extract barcodes and histological types from clinical data
clinical_data = env['data_4']
patient_histology = {}
for row in clinical_data:
    desc = row['Patient_description']
    hist_type = row['histological_type']
    if hist_type and not hist_type.startswith('['):
        match = re.search(r'TCGA-[A-Z0-9]{2}-[A-Z0-9]{4}', desc)
        if match:
            barcode = match.group()
            patient_histology[barcode] = hist_type

# Extract mutated patients
mutated_patients = set()
for row in env['data_2']:
    mutated_patients.add(row['ParticipantBarcode'])

# Build contingency table
contingency = {}
for barcode, hist_type in patient_histology.items():
    if hist_type not in contingency:
        contingency[hist_type] = {'mutated': 0, 'not_mutated': 0}
    if barcode in mutated_patients:
        contingency[hist_type]['mutated'] += 1
    else:
        contingency[hist_type]['not_mutated'] += 1

# Filter by marginal totals > 10
filtered_contingency = {}
for hist_type, counts in contingency.items():
    row_total = counts['mutated'] + counts['not_mutated']
    if row_total > 10:
        filtered_contingency[hist_type] = counts

# Calculate chi-square
grand_total = 0
col_totals = {'mutated': 0, 'not_mutated': 0}
for hist_type, counts in filtered_contingency.items():
    row_total = counts['mutated'] + counts['not_mutated']
    grand_total += row_total
    col_totals['mutated'] += counts['mutated']
    col_totals['not_mutated'] += counts['not_mutated']

chi2 = 0
for hist_type, counts in filtered_contingency.items():
    row_total = counts['mutated'] + counts['not_mutated']
    for col in ['mutated', 'not_mutated']:
        observed = counts[col]
        expected = (row_total * col_totals[col]) / grand_total
        if expected > 0:
            chi2 += ((observed - expected) ** 2) / expected

print(chi2)
env['_answer'] = chi2

